import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.reactive.function.server.ServerResponse;
import reactor.core.publisher.Mono;
import okhttp3.*;

@RestController
public class WebhookController {
    private final OkHttpClient httpClient = new OkHttpClient();

    @PostMapping(value = "/webhooks", consumes = MediaType.APPLICATION_JSON_VALUE, produces = MediaType.APPLICATION_JSON_VALUE)
    public Mono<ServerResponse> handleWebhook(@RequestBody WebhookRequest request) {
        return Mono.fromCallable(() -> fetchContent(request))
                .flatMap(response -> ServerResponse.ok().bodyValue(response))
                .onErrorResume(Throwable.class, ex -> ServerResponse.badRequest().bodyValue("An error occurred while processing the webhook: " + ex.getMessage()));
    }

    private String fetchContent(WebhookRequest request) {
        Request requestBody = new Request.Builder()
                .url(request.getUrl())
                .build();
        try (Response response = httpClient.newCall(requestBody).execute()) {
            if (!response.isSuccessful()) throw new RuntimeException("Failed : HTTP error code : " + response.code());
            return response.body().string();
        } catch (IOException e) {
            throw new RuntimeException("Error ", e);
        }
    }
}